using Microsoft.ML.Data;

namespace ChurnPredictor;

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    [ColumnName("Label")]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool Churned { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

arguments.old_str:
var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();
app.MapGet("/", () => "Hello");
app.Run();

arguments.new_str:
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// Train the model and save it
var modelPath = TrainModel(Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv"));

// Register PredictionEnginePool (thread-safe for web apps)
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST to /predict");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        WillChurn = prediction.Churned,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

static string TrainModel(string dataPath)
{
    var mlContext = new MLContext(seed: 42);

    // Load data, mapping "Yes"/"No" to bool via custom mapping
    var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
        dataPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);

    var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
        .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

    Console.WriteLine("Training churn prediction model...");
    var model = pipeline.Fit(split.TrainSet);

    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);

    Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

    var modelPath = Path.Combine(Path.GetTempPath(), "churn-model.zip");
    mlContext.Model.Save(model, rawData.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");

    return modelPath;
}

