1. using Microsoft.ML;
2. using Microsoft.Extensions.ML;
3. using ChurnPredictor;
4. var builder = WebApplication.CreateBuilder(args);
5. 
6. // Train the model and save it
7. var modelPath = TrainModel(Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv"));
8. 
9. // Register PredictionEnginePool (thread-safe for web apps)
10. builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
11.     .FromFile(modelPath);
12. 
13. var app = builder.Build();
14. 
15. app.MapGet("/", () => "Churn Predictor API — POST to /predict");
16. 
17. app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
18. {
19.     var prediction = pool.Predict(customer);
20.     return Results.Ok(new
21.     {
22.         WillChurn = prediction.Churned,
23.         prediction.Probability,
24.         prediction.Score
25.     });
26. });
27. 
28. app.Run();
29. 
30. static string TrainModel(string dataPath)
31. {
32.     var mlContext = new MLContext(seed: 42);
33. 
34.     // Load data, mapping "Yes"/"No" to bool via custom mapping
35.     var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
36.         dataPath, hasHeader: true, separatorChar: ',');
37. 
38.     // Map "Yes"/"No" string to boolean Label
39.     var pipeline = mlContext.Transforms.Conversion.MapValue("Label",
40.             new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) },
41.             "Churned")
42.         .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
43.         .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
44.         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
45.         .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());
46. 
47.     Console.WriteLine("Training churn prediction model...");
48. 
49.     long rowCount = 0;
50.     using (var cursor = rawData.GetRowCursor(rawData.Schema))
51.     {
52.         while (cursor.MoveNext()) rowCount++;
53.     }
54. 
55.     ITransformer model;
56.     if (rowCount >= 10)
57.     {
58.         var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);
59.         model = pipeline.Fit(split.TrainSet);
60. 
61.         var predictions = model.Transform(split.TestSet);
62.         var metrics = mlContext.BinaryClassification.Evaluate(predictions);
63.         Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
64.                           $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
65.     }
66.     else
67.     {
68.         Console.WriteLine($"Warning: Only {rowCount} rows — training on full dataset, skipping evaluation. " +
69.                           "Add more data for reliable metrics.");
70.         model = pipeline.Fit(rawData);
71.     }
72. 
73.     var modelPath = Path.Combine(Path.GetTempPath(), "churn-model.zip");
74.     mlContext.Model.Save(model, rawData.Schema, modelPath);
75.     Console.WriteLine($"Model saved to {modelPath}");
