 static string TrainModel(string dataPath)
 {
     var mlContext = new MLContext(seed: 42);

     // Load data, mapping "Yes"/"No" to bool via custom mapping
     var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
         dataPath, hasHeader: true, separatorChar: ',');

     // Map "Yes"/"No" string to boolean Label
     var pipeline = mlContext.Transforms.Conversion.MapValue("Label",
             new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) },
             "Churned")
         .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
         .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
         .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

     Console.WriteLine("Training churn prediction model...");

     long rowCount = 0;
     using (var cursor = rawData.GetRowCursor(rawData.Schema))
     {
         while (cursor.MoveNext()) rowCount++;
     }

     ITransformer model;
     if (rowCount >= 10)
     {
         var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);
         model = pipeline.Fit(split.TrainSet);

         var predictions = model.Transform(split.TestSet);
         var metrics = mlContext.BinaryClassification.Evaluate(predictions);
         Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                           $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
     }
     else
     {
         Console.WriteLine($"Warning: Only {rowCount} rows — training on full dataset, skipping evaluation. " +
                           "Add more data for reliable metrics.");
         model = pipeline.Fit(rawData);
     }

     var modelPath = Path.Combine(Path.GetTempPath(), "churn-model.zip");
     mlContext.Model.Save(model, rawData.Schema, modelPath);
     Console.WriteLine($"Model saved to {modelPath}");

     return modelPath;
 }

